from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity
from functools import wraps

app = Flask(__name__)

# Mock database
users_db = {
    1: {
        "id": 1,
        "email": "user@example.com",
        "username": "testuser",
        "account_type": "basic",
        "credits": 100,
        "referral_code": "ABC123",
        "verified_status": False,
        "role": "user"
    }
}

# Mock tenant check
def check_tenant(user_id, current_user_id):
    return user_id == current_user_id

# Mock role check
def check_role(user_role, required_role):
    roles = ["user", "admin", "super_admin"]
    return roles.index(user_role) >= roles.index(required_role)

# Update fields allowed per role
UPDATE_FIELDS = {
    "user": ["email", "username", "account_type", "credits", "referral_code", "verified_status"],
    "admin": ["email", "username", "account_type", "credits", "referral_code", "verified_status"],
    "super_admin": ["email", "username", "account_type", "credits", "referral_code", "verified_status"]
}

def authorize_update_fields(required_role):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            current_user_id = get_jwt_identity()
            current_user = users_db.get(current_user_id)
            
            if not current_user:
                return jsonify({"error": "User not found"}), 404
                
            if not check_role(current_user["role"], required_role):
                return jsonify({"error": "Insufficient permissions"}), 403
                
            return f(*args, **kwargs)
        return decorated_function
    return decorator

@app.route('/profile', methods=['PUT'])
@jwt_required()
@authorize_update_fields("user")
def update_profile():
    current_user_id = get_jwt_identity()
    current_user = users_db.get(current_user_id)
    
    if not current_user:
        return jsonify({"error": "User not found"}), 404
        
    update_data = request.get_json()
    
    # Validate fields
    allowed_fields = UPDATE_FIELDS[current_user["role"]]
    for field in update_data:
        if field not in allowed_fields:
            return jsonify({"error": f"Field {field} cannot be updated"}), 400
            
    # Check tenant authorization
    if not check_tenant(current_user_id, current_user_id):
        return jsonify({"error": "Unauthorized access"}), 403
        
    # Update fields
    for field, value in update_data.items():
        if field in current_user:
            current_user[field] = value
            
    return jsonify({"message": "Profile updated successfully", "user": current_user}), 200